export function PrototypeIcon({ name, size = 16, className = "", filled = false, dual = false }: PrototypeIconProps) {
  const idSuffix = useId().replace(/[^a-zA-Z0-9_-]/g, "");
  const lineSvg = getPrototypeSvg(name, false, idSuffix + "l");
  const fillSvg = getPrototypeSvg(name, true, idSuffix + "f");

  return (
    <span
      className={[
        "mewmo-prototype-icon",
        dual ? "mewmo-prototype-icon--dual" : "",
        filled ? "mewmo-prototype-icon--filled" : "",
        className,
      ]
        .filter(Boolean)
        .join(" ")}
      style={{ width: size, height: size }}
      aria-hidden="true"
    >
      {dual ? (
        <>
          <span className="mewmo-prototype-icon__line" dangerouslySetInnerHTML={{ __html: lineSvg }} />
          <span className="mewmo-prototype-icon__fill" dangerouslySetInnerHTML={{ __html: fillSvg }} />
        </>
      ) : (
        <span
          className={filled ? "mewmo-prototype-icon__fill" : "mewmo-prototype-icon__line"}
          dangerouslySetInnerHTML={{ __html: filled ? fillSvg : lineSvg }}
        />
      )}
    </span>
  );
}

export function PinIcon({ size = 13 }: { size?: number }) {
  return <PrototypeIcon name="pin" size={size} filled />;
}

export function MewmoLogo({ className = "" }: { className?: string }) {
  return <PrototypeIcon name="mewmo-logo" size={22} className={className} />;
}

function getPrototypeSvg(name: PrototypeIconName, filled: boolean, idSuffix: string) {
  if (filled) {
    const override = FILLED_NAME_OVERRIDES[name];
    const svg =
      override
        ? PROTOTYPE_EXTRA_FILL_ICONS[override]
        : PROTOTYPE_CHROME_ICONS[name as keyof typeof PROTOTYPE_CHROME_ICONS] ??
          PROTOTYPE_FILL_ICONS[name as keyof typeof PROTOTYPE_FILL_ICONS] ??
          PROTOTYPE_ACCOUNT_ICONS[name as keyof typeof PROTOTYPE_ACCOUNT_ICONS] ??
          PROTOTYPE_ACTION_ICONS[name as keyof typeof PROTOTYPE_ACTION_ICONS] ??
          PROTOTYPE_LINE_ICONS[name as keyof typeof PROTOTYPE_LINE_ICONS] ??
          "";
    return uniquifyPrototypeSvgIds(svg, idSuffix);
  }

  const svg =
    PROTOTYPE_CHROME_ICONS[name as keyof typeof PROTOTYPE_CHROME_ICONS] ??
    PROTOTYPE_LINE_ICONS[name as keyof typeof PROTOTYPE_LINE_ICONS] ??
    PROTOTYPE_ACCOUNT_ICONS[name as keyof typeof PROTOTYPE_ACCOUNT_ICONS] ??
    PROTOTYPE_ACTION_ICONS[name as keyof typeof PROTOTYPE_ACTION_ICONS] ??
    "";
  return uniquifyPrototypeSvgIds(svg, idSuffix);
}

function uniquifyPrototypeSvgIds(svg: string | undefined, idSuffix: string) {
  if (!svg) return "";
  if (!svg.includes('id="')) return svg;

  return svg
    .replace(/id="([^"]+)"/g, (_, id: string) => 'id="' + id + idSuffix + '"')
    .replace(/url\(#([^)"]+)\)/g, (_, id: string) => 'url(#' + id + idSuffix + ')');
}
